import { decodeSencode, encodeSudoku } from '@sudoku/sencode';
import { generateSudoku, solveSudoku } from '@sudoku/sudoku';
import { derived, get, writable } from 'svelte/store';
import { createGame, createSudoku } from '../../../domain/index.js';
import { hints } from './hints';

function createEmptyGrid() {
	return Array.from({ length: 9 }, () => Array(9).fill(0));
}

function createViewState(game) {
	const sudoku = game.getSudoku();

	return {
		puzzleGrid: sudoku.getPuzzleGrid(),
		grid: sudoku.getGrid(),
		invalidCells: sudoku.getInvalidCells(),
		won: sudoku.isSolved(),
		canUndo: game.canUndo(),
		canRedo: game.canRedo(),
	};
}

function createGameStore() {
	const store = writable(null);
	let game = createGame({ sudoku: createSudoku(createEmptyGrid()) });

	const publish = () => {
		store.set(createViewState(game));
	};

	const startWithPuzzle = (puzzleGrid) => {
		game = createGame({ sudoku: createSudoku(puzzleGrid) });
		publish();
	};

	const guess = (pos, value) => {
		if (!pos || pos.x === null || pos.y === null) {
			return false;
		}

		const changed = game.guess({ row: pos.y, col: pos.x, value });
		if (changed) {
			publish();
		}

		return changed;
	};

	publish();

	return {
		subscribe: store.subscribe,

		startWithPuzzle,

		generate(difficulty) {
			startWithPuzzle(generateSudoku(difficulty));
		},

		decodeSencode(sencode) {
			startWithPuzzle(decodeSencode(sencode));
		},

		guess,

		applyHint(pos) {
			if (!pos || pos.x === null || pos.y === null) {
				return false;
			}

			if (get(hints) <= 0) {
				return false;
			}

			const sudoku = game.getSudoku();
			if (sudoku.isFixedCell(pos.y, pos.x) || sudoku.getGrid()[pos.y][pos.x] !== 0) {
				return false;
			}

			const solvedGrid = solveSudoku(sudoku.getGrid());
			const hintedValue = solvedGrid[pos.y][pos.x];
			if (!Number.isInteger(hintedValue) || hintedValue === 0) {
				return false;
			}

			const changed = guess(pos, hintedValue);
			if (changed) {
				hints.useHint();
			}

			return changed;
		},

		undo() {
			const changed = game.undo();
			if (changed) {
				publish();
			}

			return changed;
		},

		redo() {
			const changed = game.redo();
			if (changed) {
				publish();
			}

			return changed;
		},

		canUndo() {
			return get(store).canUndo;
		},

		canRedo() {
			return get(store).canRedo;
		},

		getGame() {
			return game;
		},
	};
}

export const gameState = createGameStore();

const puzzleGridStore = derived(gameState, ($gameState) => $gameState.puzzleGrid);
const currentGridStore = derived(gameState, ($gameState) => $gameState.grid);

export const grid = {
	subscribe: puzzleGridStore.subscribe,

	generate(difficulty) {
		gameState.generate(difficulty);
	},

	decodeSencode(sencode) {
		gameState.decodeSencode(sencode);
	},

	get(gridStore, x, y) {
		return gridStore[y][x];
	},

	getSencode(gridStore) {
		return encodeSudoku(gridStore);
	},
};

export const userGrid = {
	subscribe: currentGridStore.subscribe,

	set(pos, value) {
		return gameState.guess(pos, value);
	},

	applyHint(pos) {
		return gameState.applyHint(pos);
	},

	undo() {
		return gameState.undo();
	},

	redo() {
		return gameState.redo();
	},

	canUndo() {
		return gameState.canUndo();
	},

	canRedo() {
		return gameState.canRedo();
	},
};

export const invalidCells = derived(gameState, ($gameState) => $gameState.invalidCells, []);
